int factorial(int n) {
    if (n <= 1) return 1;         // base case
    return n * factorial(n - 1);  // recursive case
}

int fibonacci(int n) {
    if (n <= 1) return n;  // base: fib(0)=0, fib(1)=1
    return fibonacci(n - 1) + fibonacci(n - 2);
}

int main() {
    cout << factorial(5) << endl;   // 120
    cout << fibonacci(6) << endl;   // 8
}

