// Recursive factorial
int factRec(int n) {
    if (n <= 1) return 1;
    return n * factRec(n - 1);
}

// Iterative factorial
int factIter(int n) {
    int result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

// Iterative DFS using explicit stack
void dfsIterative(unordered_map<int,vector<int>>& graph, int start) {
    stack<int> st;
    unordered_set<int> visited;
    st.push(start);
    while (!st.empty()) {
        int node = st.top(); st.pop();
        if (visited.count(node)) continue;
        visited.insert(node);
        cout << node << " ";
        for (int nbr : graph[node]) st.push(nbr);
    }
}

